const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [tracks, setTracks] = useState<LearningTrack[]>(DEFAULT_TRACKS);
  const [projects, setProjects] = useState<Project[]>(DEMO_PROJECTS);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [draggedProjectId, setDraggedProjectId] = useState<string | null>(null);
  const [selectedTrackId, setSelectedTrackId] = useState<string | null>(null);
  const [selectedSubcategoryId, setSelectedSubcategoryId] = useState<string | null>(null);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (loginUsername === 'EPEDUSUPPORT' && loginPassword === '12345678') {
      setIsAuthenticated(true);
      setLoginError('');
      setShowLoginModal(false);
      setLoginUsername('');
      setLoginPassword('');
    } else {
      setLoginError('Invalid credentials. Please try again.');
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentView('home');
  };

  const getYoutubeThumbnail = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      let videoId = '';
      if (urlObj.hostname.includes('youtu.be')) {
        videoId = urlObj.pathname.slice(1);
      } else if (urlObj.hostname.includes('youtube.com')) {
        videoId = urlObj.searchParams.get('v') || '';
      }
      return videoId ? `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg` : null;
    } catch (e) { return null; }
  };

  const getProjectDisplayThumbnail = (p: Project) => {
    const isDefault = p.thumbnail.includes('unsplash.com/photo-1498050108023-c5249f4df085');
    if (!isDefault && p.thumbnail) return p.thumbnail;
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) {
      const ytThumb = getYoutubeThumbnail(videoUrl);
      if (ytThumb) return ytThumb;
    }
    return p.thumbnail;
  };

  const handleCreateProject = (trackId?: string, subcategoryId?: string) => {
    if (!isAuthenticated) return;
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Tutorial Title',
      thumbnail: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?q=80&w=1000&auto=format&fit=crop',
      status: ProjectStatus.DRAFT,
      lastEdited: 'Just now',
      trackId: trackId || selectedTrackId || tracks[0]?.id || '',
      subcategoryId: subcategoryId || selectedSubcategoryId || undefined,
      sections: []
    };
    setSelectedProject(newProject);
    setCurrentView('editor');
  };

  const handleSaveProject = (updated: Project) => {
    setProjects(prev => {
      const exists = prev.find(p => p.id === updated.id);
      if (exists) return prev.map(p => (p.id === updated.id ? updated : p));
      return [updated, ...prev];
    });
    setCurrentView('home');
    setSelectedProject(null);
  };

  const handleProjectClick = (p: Project) => {
    setSelectedProject(p);
    setCurrentView('viewer');
  };

  const onProjectDragStart = (e: React.DragEvent, id: string) => {
    if (!isAuthenticated) return;
    setDraggedProjectId(id);
    e.dataTransfer.setData('projectId', id);
  };

  const onProjectDragOver = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    if (!isAuthenticated || !draggedProjectId || draggedProjectId === targetId) return;
    const draggedIdx = projects.findIndex(p => p.id === draggedProjectId);
    const targetIdx = projects.findIndex(p => p.id === targetId);
    const draggedProj = projects[draggedIdx];
    const targetProj = projects[targetIdx];
    if (draggedProj.trackId !== targetProj.trackId || draggedProj.subcategoryId !== targetProj.subcategoryId) return;
    const newProjects = [...projects];
    const [movedProject] = newProjects.splice(draggedIdx, 1);
    newProjects.splice(targetIdx, 0, movedProject);
    setProjects(newProjects);
  };

  const onProjectDragEnd = () => {
    setDraggedProjectId(null);
  };

  const filteredProjects = projects.filter(p => 
    p.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const renderProjectCard = (project: Project) => {
    const displayImg = getProjectDisplayThumbnail(project);
    const isDragging = draggedProjectId === project.id;
    return (
      <div 
        key={project.id}
        draggable={isAuthenticated}
        onDragStart={(e) => onProjectDragStart(e, project.id)}
        onDragOver={(e) => onProjectDragOver(e, project.id)}
        onDragEnd={onProjectDragEnd}
        className={`group bg-white rounded-[2rem] sm:rounded-[3.5rem] border-2 border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-purple-700/20 transition-all duration-500 cursor-pointer ${
          isAuthenticated ? 'cursor-grab active:cursor-grabbing' : ''
        } hover:border-purple-400 ${
          isDragging ? 'opacity-20 scale-95 border-purple-500' : 'opacity-100'
        }`}
        onClick={() => handleProjectClick(project)}
      >
        <div className="relative aspect-video overflow-hidden border-b-2 border-slate-100">
          <img 
            src={displayImg} 
            alt={project.title}
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-slate-950/0 group-hover:bg-purple-950/40 transition-all duration-500" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-500">
             <div className="w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-full flex items-center justify-center text-purple-700 shadow-2xl scale-75 group-hover:scale-100 transition-transform duration-500">
               <div className="scale-125">{ICONS.Play}</div>
             </div>
          </div>
        </div>
        <div className="p-6 sm:p-8">
          <div className="flex items-center gap-2 mb-4">
            <span className="px-3 py-1 bg-purple-700 text-white rounded-[1rem] text-[9px] font-black uppercase tracking-widest shadow-lg shadow-purple-200">
              {project.status}
            </span>
          </div>
          <h4 className="text-[14px] sm:text-[16px] font-black text-slate-950 uppercase tracking-tight group-hover:text-purple-700 transition-colors line-clamp-2 leading-tight">
            {project.title}
          </h4>
          <div className="flex items-center justify-between mt-4 sm:mt-6 pt-4 sm:pt-6 border-t-2 border-slate-100">
             <span className="text-[9px] sm:text-[10px] font-black text-slate-600 uppercase tracking-widest">{project.lastEdited}</span>
             <div className="text-[9px] sm:text-[10px] font-black text-purple-700 uppercase flex items-center gap-2 group-hover:translate-x-1 transition-transform">
               LEARN {ICONS.External}
             </div>
          </div>
        </div>
      </div>
    );
  };

  const renderAddPlaceholder = (trackId: string, subcategoryId?: string) => {
    if (!isAuthenticated) return null;
    return (
      <div 
        key={`add-${trackId}-${subcategoryId || 'main'}`}
        onClick={() => handleCreateProject(trackId, subcategoryId)}
        className="group aspect-video xl:aspect-auto xl:h-full min-h-[200px] sm:min-h-[250px] border-4 border-dashed border-slate-200 rounded-[2rem] sm:rounded-[3.5rem] bg-white/50 flex flex-col items-center justify-center gap-4 hover:border-purple-600 hover:bg-purple-50 transition-all cursor-pointer shadow-sm hover:shadow-xl"
      >
        <div className="w-12 h-12 sm:w-16 sm:h-16 rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-purple-600 group-hover:text-white transition-all shadow-inner">
          <div className="scale-125 sm:scale-150 transition-transform group-hover:rotate-90">{ICONS.Plus}</div>
        </div>
        <span className="text-[10px] sm:text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-purple-700 transition-colors">
          ADD TUTORIAL
        </span>
      </div>
    );
  };

  const visibleTracks = selectedTrackId 
    ? tracks.filter(t => t.id === selectedTrackId)
    : tracks;

  const getBreadcrumbs = () => {
    const crumbs = [];
    crumbs.push(
      <button key="all" onClick={() => { setSelectedTrackId(null); setSelectedSubcategoryId(null); }} className="hover:text-purple-700 transition-colors">
        LEARNING GALLERY
      </button>
    );
    if (selectedTrackId) {
      const track = tracks.find(t => t.id === selectedTrackId);
      crumbs.push(<span key="s1" className="text-slate-300 mx-1 sm:mx-2">/</span>);
      crumbs.push(
        <button key="track" onClick={() => setSelectedSubcategoryId(null)} className={`hover:text-purple-700 transition-colors ${!selectedSubcategoryId ? 'text-purple-700' : ''}`}>
          {track?.title}
        </button>
      );
    }
    if (selectedSubcategoryId && selectedTrackId) {
      const track = tracks.find(t => t.id === selectedTrackId);
      const sub = track?.subcategories?.find(s => s.id === selectedSubcategoryId);
      crumbs.push(<span key="s2" className="text-slate-300 mx-1 sm:mx-2">/</span>);
      crumbs.push(<span key="sub" className="text-purple-700">{sub?.title}</span>);
    }
    return crumbs;
  };

  if (currentView === 'editor' && selectedProject) {
    return (
      <ProjectEditor 
        project={selectedProject} 
        tracks={tracks} 
        onSave={handleSaveProject} 
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }} 
      />
    );
  }

  if (currentView === 'viewer' && selectedProject) {
    return (
      <ProjectViewer 
        project={selectedProject}
        track={tracks.find(t => t.id === selectedProject.trackId)}
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }}
        onEdit={() => setCurrentView('editor')}
        isAdmin={isAuthenticated}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden relative">
      {/* Login Modal */}
      {showLoginModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="w-full max-w-md bg-white rounded-[3rem] p-12 shadow-2xl animate-slide-up relative">
            <button 
              onClick={() => setShowLoginModal(false)}
              className="absolute top-8 right-8 text-slate-400 hover:text-slate-950 transition-colors"
            >
              {ICONS.Back}
            </button>
            <div className="flex flex-col items-center mb-10">
              <div className="w-16 h-16 bg-purple-700 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-purple-900/20 mb-6">
                <div className="w-8 h-8 border-4 border-white rounded-xl flex items-center justify-center">
                  <div className="w-2 h-2 bg-white rounded-full"></div>
                </div>
              </div>
              <h1 className="text-3xl font-black text-slate-950 uppercase tracking-tighter text-center">EP Admin</h1>
              <p className="text-[11px] font-black text-purple-700 uppercase tracking-[0.3em] mt-2">Tutorial Management Hub</p>
            </div>

            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-4">Username</label>
                <input 
                  type="text" 
                  value={loginUsername}
                  onChange={(e) => setLoginUsername(e.target.value)}
                  className="w-full px-8 py-4 bg-slate-100 border-2 border-transparent focus:border-purple-600 focus:bg-white rounded-2xl text-sm font-bold focus:outline-none transition-all"
                  placeholder="EPEDUSUPPORT"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-4">Password</label>
                <input 
                  type="password" 
                  value={loginPassword}
                  onChange={(e) => setLoginPassword(e.target.value)}
                  className="w-full px-8 py-4 bg-slate-100 border-2 border-transparent focus:border-purple-600 focus:bg-white rounded-2xl text-sm font-bold focus:outline-none transition-all"
                  placeholder="••••••••"
                />
              </div>

              {loginError && (
                <p className="text-[10px] font-bold text-red-500 uppercase text-center">{loginError}</p>
              )}

              <button 
                type="submit"
                className="w-full bg-purple-700 hover:bg-slate-950 text-white py-5 rounded-2xl text-[12px] font-black uppercase tracking-widest shadow-xl shadow-purple-700/20 transition-all active:scale-95"
              >
                Authorize Access
              </button>
            </form>
          </div>
        </div>
      )}

      <Sidebar 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        tracks={tracks}
        onTracksReorder={setTracks}
        selectedTrackId={selectedTrackId}
        onTrackSelect={setSelectedTrackId}
        selectedSubcategoryId={selectedSubcategoryId}
        onSubcategorySelect={setSelectedSubcategoryId}
        isAdmin={isAuthenticated}
        onAdminLogin={() => setShowLoginModal(true)}
        onAdminLogout={handleLogout}
      />
      <main className="flex-1 flex flex-col relative overflow-y-auto px-6 sm:px-12 py-8 sm:py-12 scroll-smooth no-scrollbar">
        <header className="flex flex-col xl:flex-row xl:items-center justify-between gap-8 mb-12 sm:mb-16">
          <div className="group">
            <h1 className="text-[28px] sm:text-[42px] font-black text-slate-950 leading-tight uppercase tracking-tighter flex items-center flex-wrap">
              {getBreadcrumbs()}
            </h1>
            <p className="text-[11px] sm:text-[14px] font-black text-purple-700 uppercase tracking-[0.3em] mt-1">
              EDUCATIONAL HUB • CURATED BY EXPERTS
            </p>
          </div>
          <div className="flex flex-col md:flex-row items-center gap-4 sm:gap-6">
            <div className="flex items-center gap-4 w-full md:w-auto">
              {(selectedTrackId || selectedSubcategoryId) && (
                <button 
                  onClick={() => { 
                    if (selectedSubcategoryId) setSelectedSubcategoryId(null);
                    else setSelectedTrackId(null);
                  }}
                  className="text-[9px] sm:text-[11px] font-black text-slate-500 hover:text-purple-700 uppercase tracking-widest flex items-center gap-2 transition-colors bg-white px-4 py-3 rounded-2xl border-2 border-slate-200 shadow-sm"
                >
                  {ICONS.Back} BACK
                </button>
              )}
              <div className="relative flex-1 md:w-80">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 scale-75 sm:scale-100">
                  {ICONS.Search}
                </div>
                <input 
                  type="text" 
                  placeholder="Search..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-10 sm:pl-14 pr-4 sm:pr-6 py-3 sm:py-4 bg-white border-2 border-slate-300 rounded-[1.5rem] sm:rounded-[2rem] text-[12px] sm:text-[14px] font-bold focus:outline-none focus:ring-4 focus:ring-purple-600/20 shadow-xl transition-all text-slate-950 placeholder:text-slate-500"
                />
              </div>
            </div>
            {isAuthenticated && (
              <button 
                onClick={() => handleCreateProject()}
                className="w-full md:w-auto flex items-center justify-center gap-3 bg-purple-700 text-white px-8 sm:px-10 py-4 sm:py-5 rounded-[1.5rem] sm:rounded-[2rem] text-[11px] sm:text-[13px] font-black uppercase tracking-widest hover:bg-slate-950 shadow-2xl transition-all active:scale-95"
              >
                {ICONS.Plus} ADD TUTORIAL
              </button>
            )}
          </div>
        </header>
        <div className="space-y-24 sm:space-y-32 pb-20">
          {visibleTracks.map((track) => {
            const trackProjects = filteredProjects.filter(p => p.trackId === track.id);
            const subcategoriesToRender = selectedSubcategoryId ? track.subcategories?.filter(s => s.id === selectedSubcategoryId) : track.subcategories;
            const hasSubcategories = subcategoriesToRender && subcategoriesToRender.length > 0;
            return (
              <section key={track.id} className="space-y-10 sm:space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
                {!selectedTrackId && (
                  <div className="flex items-center justify-between border-b-4 border-slate-200 pb-6 sm:pb-8 cursor-pointer group" onClick={() => setSelectedTrackId(track.id)}>
                    <div className="flex items-center gap-4 sm:gap-6">
                      <span className="text-3xl sm:text-5xl bg-white p-3 sm:p-5 rounded-[1.5rem] sm:rounded-[2.5rem] shadow-xl border-2 border-slate-100 group-hover:scale-105 transition-transform">{track.icon}</span>
                      <div>
                        <h3 className="text-xl sm:text-3xl font-black text-slate-950 uppercase tracking-tight leading-none group-hover:text-purple-700 transition-colors">{track.title}</h3>
                        <p className="text-[10px] sm:text-[13px] font-black text-slate-600 uppercase tracking-[0.2em] mt-2 sm:mt-3">{track.subtitle}</p>
                      </div>
                    </div>
                  </div>
                )}
                {hasSubcategories ? (
                  <div className="space-y-12 sm:space-y-16">
                    {subcategoriesToRender?.map(sub => {
                      const subProjects = trackProjects.filter(p => p.subcategoryId === sub.id);
                      return (
                        <div key={sub.id} className="space-y-6 sm:space-y-8 pl-3 sm:pl-4 border-l-4 border-purple-100">
                          <h4 className={`text-lg sm:text-xl font-black uppercase tracking-widest flex items-center gap-3 sm:gap-4 cursor-pointer hover:text-purple-900 transition-colors ${selectedSubcategoryId === sub.id ? 'text-purple-900' : 'text-purple-700'}`} onClick={() => setSelectedSubcategoryId(sub.id)}>
                            <span className={`w-3 h-3 sm:w-4 sm:h-4 rounded-full ${selectedSubcategoryId === sub.id ? 'bg-purple-900 scale-125' : 'bg-purple-600'}`} />
                            {sub.title}
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 sm:gap-12">
                            {subProjects.map(project => renderProjectCard(project))}
                            {renderAddPlaceholder(track.id, sub.id)}
                          </div>
                        </div>
                      );
                    })}
                    {!selectedSubcategoryId && trackProjects.filter(p => !p.subcategoryId).length > 0 && (
                      <div className="space-y-6 sm:space-y-8 pl-3 sm:pl-4">
                        <h4 className="text-lg sm:text-xl font-black text-slate-400 uppercase tracking-widest">Other Tutorials</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 sm:gap-12">
                          {trackProjects.filter(p => !p.subcategoryId).map(project => renderProjectCard(project))}
                          {renderAddPlaceholder(track.id)}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  (!selectedSubcategoryId) && (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 sm:gap-12">
                      {trackProjects.map((project) => renderProjectCard(project))}
                      {renderAddPlaceholder(track.id)}
                    </div>
                  )
                )}
              </section>
            );
          })}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { LearningTrack } from '../types';

interface SidebarProps {
  currentView: string;
  onViewChange: (view: any) => void;
  tracks: LearningTrack[];
  onTracksReorder: (tracks: LearningTrack[]) => void;
  selectedTrackId: string | null;
  onTrackSelect: (id: string | null) => void;
  selectedSubcategoryId: string | null;
  onSubcategorySelect: (id: string | null) => void;
  isAdmin: boolean;
  onAdminLogin: () => void;
  onAdminLogout: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, 
  onViewChange, 
  tracks, 
  onTracksReorder, 
  selectedTrackId, 
  onTrackSelect,
  selectedSubcategoryId,
  onSubcategorySelect,
  isAdmin,
  onAdminLogin,
  onAdminLogout
}) => {
  const [draggedTrackIndex, setDraggedTrackIndex] = useState<number | null>(null);
  const [draggedSubIndex, setDraggedSubIndex] = useState<{ trackIdx: number, subIdx: number } | null>(null);
  const [expandedTrackIds, setExpandedTrackIds] = useState<Set<string>>(new Set(tracks.map(t => t.id)));

  // Inline adding state
  const [addingTrack, setAddingTrack] = useState(false);
  const [newTrackName, setNewTrackName] = useState('');
  const [addingSubToTrackId, setAddingSubToTrackId] = useState<string | null>(null);
  const [newSubName, setNewSubName] = useState('');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if ((addingTrack || addingSubToTrackId) && inputRef.current) {
      inputRef.current.focus();
    }
  }, [addingTrack, addingSubToTrackId]);

  const toggleTrackExpansion = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newExpanded = new Set(expandedTrackIds);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedTrackIds(newExpanded);
  };

  const handleTrackClick = (id: string) => {
    onTrackSelect(id);
    onSubcategorySelect(null);
    onViewChange('home');
    if (!expandedTrackIds.has(id)) {
      setExpandedTrackIds(prev => new Set(prev).add(id));
    }
  };

  const handleSubcategoryClick = (e: React.MouseEvent, trackId: string, subId: string) => {
    e.stopPropagation();
    onTrackSelect(trackId);
    onSubcategorySelect(subId);
    onViewChange('home');
  };

  const submitNewTrack = () => {
    if (!newTrackName.trim()) {
      setAddingTrack(false);
      return;
    }

    const newTrack: LearningTrack = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTrackName.toUpperCase(),
      subtitle: `VIDEO TUTORIALS FOR ${newTrackName.toUpperCase()}`,
      icon: '📚',
      subcategories: []
    };

    onTracksReorder([...tracks, newTrack]);
    setExpandedTrackIds(prev => new Set(prev).add(newTrack.id));
    setNewTrackName('');
    setAddingTrack(false);
  };

  const submitNewSubcategory = (trackId: string) => {
    if (!newSubName.trim()) {
      setAddingSubToTrackId(null);
      return;
    }

    const newTracks = tracks.map(track => {
      if (track.id === trackId) {
        const subs = track.subcategories || [];
        return {
          ...track,
          subcategories: [...subs, { id: Math.random().toString(36).substr(2, 9), title: newSubName }]
        };
      }
      return track;
    });

    onTracksReorder(newTracks);
    setNewSubName('');
    setAddingSubToTrackId(null);
  };

  const handleDeleteTrack = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!isAdmin) return;
    if (confirm("Delete this track and all its contents?")) {
      onTracksReorder(tracks.filter(t => t.id !== id));
      if (selectedTrackId === id) {
        onTrackSelect(null);
        onSubcategorySelect(null);
      }
    }
  };

  const handleDeleteSub = (e: React.MouseEvent, trackId: string, subId: string) => {
    e.stopPropagation();
    if (!isAdmin) return;
    const newTracks = tracks.map(t => {
      if (t.id === trackId) {
        return { ...t, subcategories: t.subcategories?.filter(s => s.id !== subId) };
      }
      return t;
    });
    onTracksReorder(newTracks);
    if (selectedSubcategoryId === subId) onSubcategorySelect(null);
  };

  // Drag & Drop logic
  const onTrackDragStart = (_e: React.DragEvent, index: number) => {
    if (!isAdmin) return;
    setDraggedTrackIndex(index);
    setDraggedSubIndex(null);
  };

  const onTrackDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (!isAdmin || draggedTrackIndex === null || draggedTrackIndex === index) return;
    const newTracks = [...tracks];
    const [item] = newTracks.splice(draggedTrackIndex, 1);
    newTracks.splice(index, 0, item);
    setDraggedTrackIndex(index);
    onTracksReorder(newTracks);
  };

  const onSubDragStart = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    if (!isAdmin) return;
    e.stopPropagation();
    setDraggedSubIndex({ trackIdx, subIdx });
    setDraggedTrackIndex(null);
  };

  const onSubDragOver = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.preventDefault();
    e.stopPropagation();
    if (!isAdmin || !draggedSubIndex || draggedSubIndex.trackIdx !== trackIdx || draggedSubIndex.subIdx === subIdx) return;

    const newTracks = JSON.parse(JSON.stringify(tracks)) as LearningTrack[];
    const track = newTracks[trackIdx];
    if (!track.subcategories) return;

    const [item] = track.subcategories.splice(draggedSubIndex.subIdx, 1);
    track.subcategories.splice(subIdx, 0, item);

    setDraggedSubIndex({ trackIdx, subIdx });
    onTracksReorder(newTracks);
  };

  return (
    <div className="w-80 h-screen bg-white border-r border-slate-200 flex flex-col py-8 px-4 relative shadow-sm shrink-0">
      <div className="flex items-center gap-3 px-2 mb-10 overflow-hidden whitespace-nowrap">
        <div className="w-10 h-10 shrink-0 bg-purple-700 rounded-xl flex items-center justify-center text-white shadow-lg shadow-purple-200">
          <div className="w-5 h-5 border-2 border-white rounded-lg flex items-center justify-center">
            <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
          </div>
        </div>
        <div>
          <h2 className="text-sm font-black text-slate-900 leading-none tracking-tight">LEARNING</h2>
          <p className="text-[11px] font-bold text-purple-700 tracking-widest mt-0.5">GALLERY</p>
        </div>
      </div>

      <div className="space-y-1">
        <button
          onClick={() => {
            onViewChange('home');
            onTrackSelect(null);
            onSubcategorySelect(null);
          }}
          className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all overflow-hidden whitespace-nowrap ${
            currentView === 'home' && selectedTrackId === null
            ? 'bg-purple-700 text-white shadow-lg shadow-purple-200' 
            : 'text-slate-700 hover:bg-slate-100'
          }`}
        >
          {ICONS.Home}
          <span>HOME PAGE</span>
        </button>
      </div>

      <div className="mt-10 flex-1 overflow-y-auto no-scrollbar">
        <div className="px-4 flex items-center justify-between mb-6">
          <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-widest">LEARNING TRACKS</h3>
          {isAdmin && (
            <button 
              onClick={() => setAddingTrack(true)}
              className="p-1.5 hover:bg-slate-100 rounded-lg text-purple-700 transition-colors"
            >
              {ICONS.Plus}
            </button>
          )}
        </div>

        {addingTrack && (
          <div className="px-4 mb-4">
            <input
              ref={inputRef}
              value={newTrackName}
              onChange={(e) => setNewTrackName(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && submitNewTrack()}
              onBlur={submitNewTrack}
              placeholder="New Track Name..."
              className="w-full px-3 py-2 text-xs font-bold uppercase tracking-widest border-2 border-purple-300 rounded-lg focus:outline-none focus:border-purple-600 bg-white text-slate-950 shadow-sm"
            />
          </div>
        )}

        <div className="space-y-2">
          {tracks.map((track, tIdx) => (
            <div key={track.id} className="space-y-1">
              <div
                draggable={isAdmin}
                onDragStart={(e) => onTrackDragStart(e, tIdx)}
                onDragOver={(e) => onTrackDragOver(e, tIdx)}
                onDragEnd={() => setDraggedTrackIndex(null)}
                onClick={() => handleTrackClick(track.id)}
                className={`group flex items-center gap-3 px-4 py-3.5 rounded-xl transition-all border border-transparent ${
                  isAdmin ? 'cursor-grab active:cursor-grabbing' : 'cursor-pointer'
                } ${
                  selectedTrackId === track.id && selectedSubcategoryId === null
                    ? 'bg-purple-100 border-purple-200 text-purple-900 shadow-sm' 
                    : 'hover:bg-slate-50 hover:border-slate-200 text-slate-900'
                } ${draggedTrackIndex === tIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'}`}
              >
                <span className="text-xl shrink-0">{track.icon}</span>
                <span className="flex-1 text-[12px] font-bold tracking-wide uppercase truncate">
                  {track.title}
                </span>
                {isAdmin && (
                  <button 
                    onClick={(e) => handleDeleteTrack(e, track.id)}
                    className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all"
                  >
                    {ICONS.Delete}
                  </button>
                )}
                <div 
                  onClick={(e) => toggleTrackExpansion(e, track.id)}
                  className={`p-1 text-slate-400 hover:text-purple-600 transition-transform duration-300 ${expandedTrackIds.has(track.id) ? 'rotate-180' : ''}`}
                >
                  {ICONS.ChevronDown}
                </div>
              </div>

              {expandedTrackIds.has(track.id) && (
                <div className="ml-10 space-y-1 animate-in slide-in-from-top-2 duration-200">
                  {track.subcategories?.map((sub, sIdx) => (
                    <div
                      key={sub.id}
                      draggable={isAdmin}
                      onDragStart={(e) => onSubDragStart(e, tIdx, sIdx)}
                      onDragOver={(e) => onSubDragOver(e, tIdx, sIdx)}
                      onDragEnd={() => setDraggedSubIndex(null)}
                      onClick={(e) => handleSubcategoryClick(e, track.id, sub.id)}
                      className={`group flex items-center gap-3 px-4 py-2.5 rounded-lg transition-all border border-transparent ${
                        isAdmin ? 'cursor-grab active:cursor-grabbing' : 'cursor-pointer'
                      } ${
                        selectedSubcategoryId === sub.id 
                          ? 'bg-purple-50 border-purple-100 text-purple-700' 
                          : 'hover:bg-slate-50 hover:border-slate-200 text-slate-600'
                      } ${draggedSubIndex?.trackIdx === tIdx && draggedSubIndex?.subIdx === sIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'}`}
                    >
                      <div className={`w-1.5 h-1.5 rounded-full transition-colors ${selectedSubcategoryId === sub.id ? 'bg-purple-700' : 'bg-slate-300 group-hover:bg-purple-500'}`} />
                      <span className={`flex-1 text-[11px] font-bold tracking-wide uppercase truncate ${selectedSubcategoryId === sub.id ? 'text-purple-900' : 'group-hover:text-slate-900'}`}>
                        {sub.title}
                      </span>
                      {isAdmin && (
                        <button 
                          onClick={(e) => handleDeleteSub(e, track.id, sub.id)}
                          className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all scale-75"
                        >
                          {ICONS.Delete}
                        </button>
                      )}
                    </div>
                  ))}

                  {isAdmin && (addingSubToTrackId === track.id ? (
                    <div className="px-4 py-2">
                      <input
                        ref={inputRef}
                        value={newSubName}
                        onChange={(e) => setNewSubName(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && submitNewSubcategory(track.id)}
                        onBlur={() => submitNewSubcategory(track.id)}
                        placeholder="Subcategory..."
                        className="w-full px-2 py-1 text-[10px] font-bold uppercase tracking-widest border border-purple-300 rounded focus:outline-none bg-white text-slate-950 shadow-sm"
                      />
                    </div>
                  ) : (
                    <button
                      onClick={(e) => { e.stopPropagation(); setAddingSubToTrackId(track.id); }}
                      className="w-full flex items-center gap-3 px-4 py-2 text-[10px] font-black text-purple-600/60 uppercase tracking-widest hover:text-purple-700 hover:bg-purple-50 rounded-lg transition-all"
                    >
                      <span className="scale-75">{ICONS.Plus}</span>
                      ADD SUBCATEGORY
                    </button>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <button 
        onClick={isAdmin ? onAdminLogout : onAdminLogin}
        className="mt-auto mx-2 flex items-center justify-center gap-2 py-3.5 px-4 rounded-xl bg-slate-900 text-white text-[11px] font-bold uppercase tracking-widest hover:bg-purple-800 transition-all shadow-md"
      >
        {isAdmin ? <>{ICONS.Back} LOGOUT</> : <>{ICONS.Admin} ADMIN LOGIN</>}
      </button>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { Project, LearningTrack } from '../types';
import { ICONS } from '../constants';
import VideoPlayer from './VideoPlayer';

interface ProjectViewerProps {
  project: Project;
  track?: LearningTrack;
  onBack: () => void;
  onEdit: () => void;
  isAdmin: boolean;
}

const ProjectViewer: React.FC<ProjectViewerProps> = ({ project, track, onBack, onEdit, isAdmin }) => {
  const [showHeroVideo, setShowHeroVideo] = useState(false);

  const getYoutubeUrl = (videoUrl: string) => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
    const match = videoUrl.match(regExp);
    const id = (match && match[7].length === 11) ? match[7] : null;
    return id ? `https://www.youtube.com/watch?v=${id}` : videoUrl;
  };

  const getYoutubeThumbnail = (videoUrl: string) => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
    const match = videoUrl.match(regExp);
    const id = (match && match[7].length === 11) ? match[7] : null;
    return id ? `https://img.youtube.com/vi/${id}/maxresdefault.jpg` : null;
  };

  const firstVideo = React.useMemo(() => {
    return project.sections
      .flatMap(s => s.blocks)
      .find(b => b.type === 'video' && b.content);
  }, [project]);

  const displayThumbnail = React.useMemo(() => {
    const isDefault = project.thumbnail.includes('unsplash.com/photo-1498050108023-c5249f4df085');
    if (!isDefault && project.thumbnail) return project.thumbnail;

    if (firstVideo?.content) {
      const ytThumb = getYoutubeThumbnail(firstVideo.content);
      if (ytThumb) return ytThumb;
    }
    return project.thumbnail;
  }, [project, firstVideo]);

  const getSectionBg = (bg?: string) => {
    switch(bg) {
      case 'gray': return 'bg-slate-100';
      case 'purple': return 'bg-gradient-to-br from-purple-50 to-white';
      case 'dark': return 'bg-slate-900 text-white';
      default: return 'bg-white';
    }
  };

  return (
    <div className="flex flex-col h-screen bg-white overflow-y-auto no-scrollbar">
      {/* Viewer Navigation */}
      <nav className="sticky top-0 z-50 bg-white/95 backdrop-blur-xl border-b-2 border-slate-200 px-8 py-5 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-3 hover:bg-slate-100 rounded-2xl transition-all text-slate-900 shadow-sm border border-slate-200">
            {ICONS.Back}
          </button>
          <div>
            <h2 className="text-base font-black text-slate-950 uppercase tracking-tight leading-none">
              {project.title}
            </h2>
            <div className="flex items-center gap-3 mt-1.5">
              <span className="text-[11px] font-black text-purple-700 uppercase tracking-widest">{track?.title || 'Course Content'}</span>
              <span className="w-1.5 h-1.5 bg-slate-300 rounded-full"></span>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest">{project.lastEdited}</span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {firstVideo?.content && (
             <button 
              onClick={() => window.open(getYoutubeUrl(firstVideo.content), '_blank')}
              className="flex items-center gap-3 bg-white border-2 border-slate-300 text-slate-950 px-8 py-3.5 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all shadow-sm"
             >
               {ICONS.External} SOURCE
             </button>
          )}
          {isAdmin && (
            <button 
              onClick={onEdit}
              className="flex items-center gap-3 bg-slate-950 text-white px-8 py-3.5 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-purple-800 transition-all shadow-xl"
            >
              {ICONS.Settings} CONFIGURE
            </button>
          )}
        </div>
      </nav>

      {/* Hero Header */}
      <header className="relative h-[70vh] bg-slate-950 flex items-center justify-center overflow-hidden">
        {showHeroVideo && firstVideo?.content ? (
          <div className="absolute inset-0 w-full h-full z-20">
             <VideoPlayer url={firstVideo.content} autoPlay={true} className="rounded-none h-full border-0" />
             <button 
               onClick={() => setShowHeroVideo(false)}
               className="absolute top-8 right-8 z-40 p-4 bg-black/50 text-white rounded-full hover:bg-red-600 transition-colors"
             >
               {ICONS.Back}
             </button>
          </div>
        ) : (
          <>
            <img src={displayThumbnail} className="absolute inset-0 w-full h-full object-cover opacity-50 blur-sm scale-110" alt="" />
            <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-slate-950/60 to-transparent" />
            <div className="relative z-10 text-center px-10 max-w-5xl">
              <div className="inline-block px-8 py-3 bg-purple-700 rounded-full text-[11px] font-black text-white uppercase tracking-[0.4em] mb-12 shadow-2xl border border-white/10">
                EXCELLENCE IN LEARNING
              </div>
              <h1 className="text-7xl md:text-9xl font-black text-white uppercase tracking-tighter leading-[0.85] drop-shadow-2xl">
                {project.title}
              </h1>
              <div className="mt-14 flex items-center justify-center gap-8">
                 {firstVideo?.content && (
                   <button 
                    onClick={() => setShowHeroVideo(true)}
                    className="flex items-center gap-4 px-12 py-5 bg-white text-slate-950 rounded-full text-[13px] font-black uppercase tracking-[0.2em] hover:bg-purple-600 hover:text-white transition-all shadow-2xl group"
                   >
                     {ICONS.Play} Start Tutorial In-App
                   </button>
                 )}
              </div>
            </div>
          </>
        )}
      </header>

      {/* Dynamic Content Sections */}
      <main className="w-full">
        {project.sections.map((section) => (
          <div 
            key={section.id} 
            className={`${getSectionBg(section.style?.background)} ${section.style?.padding === 'compact' ? 'py-16' : section.style?.padding === 'large' ? 'py-44' : 'py-28'} border-b border-slate-100 last:border-0`}
          >
            <div className="max-w-7xl mx-auto px-12 grid grid-cols-12 gap-12 md:gap-16">
              {section.blocks.map((block) => (
                <div 
                  key={block.id} 
                  className={`col-span-12 md:col-span-${block.gridSpan || 12} flex flex-col`}
                >
                  {block.type === 'heading' && (
                    <h2 className="text-4xl font-black text-slate-950 uppercase tracking-tight mb-10 border-l-[12px] border-purple-700 pl-8 leading-none">{block.content}</h2>
                  )}
                  {block.type === 'text' && (
                    <div className="max-w-none">
                      <p className="text-slate-900 leading-relaxed text-2xl font-bold whitespace-pre-wrap">
                        {block.content}
                      </p>
                    </div>
                  )}
                  {block.type === 'image' && block.content && (
                    <div className="rounded-[4rem] overflow-hidden shadow-2xl border-4 border-white transform transition-transform hover:scale-[1.01] duration-500">
                      <img src={block.content} className="w-full h-auto" alt="Learning Material" />
                    </div>
                  )}
                  {block.type === 'video' && block.content && (
                    <VideoPlayer url={block.content} className="shadow-2xl rounded-[4rem]" />
                  )}
                  {block.type === 'divider' && (
                    <div className="py-16"><div className="h-1.5 w-full bg-slate-200 opacity-80 rounded-full shadow-inner" /></div>
                  )}
                  {block.type === 'spacer' && (
                    <div className="h-28" />
                  )}
                </div>
              ))}
            </div>
          </div>
        ))}

        {project.sections.length === 0 && (
          <div className="text-center py-56 bg-slate-50">
            <p className="text-slate-400 font-black uppercase tracking-[0.5em] text-sm">Building course content...</p>
          </div>
        )}
      </main>

      <footer className="border-t-4 border-slate-100 py-32 px-12 bg-white mt-auto">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-16">
          <div className="flex items-center gap-8">
             <div className="w-16 h-16 bg-purple-700 rounded-[2rem] flex items-center justify-center text-white text-xl font-black shadow-2xl shadow-purple-300">EP</div>
             <div className="text-left">
               <span className="block text-2xl font-black text-slate-950 uppercase tracking-tighter">Learning Gallery Hub</span>
               <span className="block text-[12px] font-black text-purple-700 uppercase tracking-widest mt-1">Universal Learning Architecture</span>
             </div>
          </div>
          <div className="flex flex-col items-center md:items-end gap-4">
            <p className="text-[12px] font-black text-slate-600 uppercase tracking-[0.3em]">© 2026 EP EDUCATION • ALL RIGHTS RESERVED</p>
            <p className="text-[11px] font-black text-slate-400 uppercase tracking-large">EXCELLENCE IN PEDAGOGICAL DESIGN</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default ProjectViewer;
